package ir.tahamohamadi.publication.api.publicsite;
import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.publication.PublicationStage; import jakarta.validation.constraints.*; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*;
@RestController @Validated @RequestMapping("/api/v1/public/{locale}/publications") public class PublicPublicationController {private final PublicPublicationService service;public PublicPublicationController(PublicPublicationService service){this.service=service;}@GetMapping public PublicPublicationListResponse list(@PathVariable LanguageCode locale,@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(50) int size,@RequestParam(required=false) PublicationStage stage){return service.list(locale,page,size,stage);}@GetMapping("/{slug}") public PublicPublicationResponse get(@PathVariable LanguageCode locale,@PathVariable @NotBlank String slug){return service.get(locale,slug);}}
